package com.restaurantcraft.blockentity;
import com.restaurantcraft.block.CookingDeviceBlock; import com.restaurantcraft.data.*; import com.restaurantcraft.menu.CookingDeviceMenu; import com.restaurantcraft.registry.*; import net.minecraft.core.*; import net.minecraft.nbt.CompoundTag; import net.minecraft.network.chat.Component; import net.minecraft.server.level.ServerPlayer; import net.minecraft.world.*; import net.minecraft.world.entity.player.*; import net.minecraft.world.inventory.AbstractContainerMenu; import net.minecraft.world.item.ItemStack; import net.minecraft.world.level.Level; import net.minecraft.world.level.block.entity.*; import net.minecraft.world.level.block.state.BlockState; import net.minecraftforge.common.capabilities.*; import net.minecraftforge.common.util.LazyOptional; import net.minecraftforge.items.*; import net.minecraftforge.network.NetworkHooks; import org.jetbrains.annotations.Nullable;
public class CookingDeviceBlockEntity extends BlockEntity implements MenuProvider { public final ItemStackHandler items=new ItemStackHandler(2){protected void onContentsChanged(int s){setChanged();}}; private final LazyOptional<IItemHandler> cap=LazyOptional.of(()->items); public int progress,maxProgress; public CookingDeviceBlockEntity(BlockPos p, BlockState s){super(ModBlockEntities.COOKING_DEVICE.get(),p,s);} public Component getDisplayName(){return Component.translatable("screen.restaurant_craft.cooking_device");} @Nullable public AbstractContainerMenu createMenu(int id, Inventory inv, Player p){return new CookingDeviceMenu(id,inv,this);} public void openMenu(ServerPlayer sp){NetworkHooks.openScreen(sp,this,worldPosition);}
 public void tick(){ if(level==null||level.isClientSide)return; ItemStack in=items.getStackInSlot(0),out=items.getStackInSlot(1); DishDefinition d=findRecipe(); if(d==null){progress=0;return;} maxProgress=d.cookTicks(); if(++progress>=maxProgress){ItemStack cooked=new ItemStack(ModItems.COOKED_DISH_ITEMS.get(d.id()).get()); if(out.isEmpty())items.setStackInSlot(1,cooked); else out.grow(1); in.shrink(1); progress=0; setChanged();} }
 private DishDefinition findRecipe(){ if(items.getStackInSlot(0).isEmpty())return null; String device=((CookingDeviceBlock)getBlockState().getBlock()).deviceId; for(DishDefinition d:DishRegistry.DISHES){ if(d.device().equals(device)&&items.getStackInSlot(0).is(ModItems.RAW_DISH_ITEMS.get(d.id()).get())){ItemStack out=items.getStackInSlot(1); return (out.isEmpty()||(out.is(ModItems.COOKED_DISH_ITEMS.get(d.id()).get())&&out.getCount()<out.getMaxStackSize()))?d:null;}} return null;}
 protected void saveAdditional(CompoundTag t){super.saveAdditional(t);t.put("Items",items.serializeNBT());t.putInt("Progress",progress);t.putInt("MaxProgress",maxProgress);} public void load(CompoundTag t){super.load(t);items.deserializeNBT(t.getCompound("Items"));progress=t.getInt("Progress");maxProgress=t.getInt("MaxProgress");} public <T> LazyOptional<T> getCapability(Capability<T> c, Direction d){return c==ForgeCapabilities.ITEM_HANDLER?cap.cast():super.getCapability(c,d);} public void invalidateCaps(){super.invalidateCaps();cap.invalidate();} }
